# Input validation patterns
POLICY_NUMBER_PATTERN = re.compile(r'^[A-Z0-9]{6,20}$')
CUSTOMER_NAME_PATTERN = re.compile(r'^[A-Za-z\s\-\.\']{1,100}$')

def validate_policy_number(policy_number: str) -> bool:
    """Validate policy number format"""
    return bool(POLICY_NUMBER_PATTERN.match(policy_number))

def validate_customer_name(customer_name: str) -> bool:
    """Validate customer name format"""
    return bool(CUSTOMER_NAME_PATTERN.match(customer_name))

def secure_input_validation(policy_number: str, customer_name: str) -> Dict[str, Any]:
    """Validate and sanitize user inputs"""
    errors = []
    
    if not validate_policy_number(policy_number):
        errors.append("Invalid policy number format")
    
    if not validate_customer_name(customer_name):
        errors.append("Invalid customer name format")
    
    if errors:
        raise ValueError(f"Input validation failed: {', '.join(errors)}")
    
    return {
        "policy_number": policy_number.strip(),
        "customer_name": customer_name.strip()
    }

def create_secure_soap_client(wsdl_url: str, username: str, password: str) -> Client:
    """Create a secure SOAP client with proper authentication"""
    session = Session()
    session.auth = HTTPBasicAuth(username, password)
    
    transport = Transport(session=session, timeout=30)
    client = Client(wsdl_url, transport=transport)
    
    return client

def build_policy_lookup_request(policy_number: str, customer_name: str) -> Dict[str, Any]:
    """Build secure SOAP request with validated inputs"""
    # Inputs are already validated and sanitized
    return {
        "PolicyNumber": policy_number,
        "CustomerName": customer_name
    }

def send_policy_lookup_request(client: Client, policy_data: Dict[str, str]) -> Any:
    """Send policy lookup request to insurance service"""
    try:
        # Use secure method call with validated parameters
        response = client.service.LookupPolicy(
            PolicyNumber=policy_data["policy_number"],
            CustomerName=policy_data["customer_name"]
        )
        return response
    except Exception as e:
        logger.error(f"SOAP request failed: {str(e)}")
        raise

